#!/usr/bin/env python3
"""
Runtime efficiency evaluation script for SMDA.

Compares reports generated by different versions (master vs upstream) to ensure
output consistency and compare execution times.
Uses caching for efficiency.

Usage: python evaluate_runtime.py

Output:
  - runtime_measurements/cache/evaluation.json: Full JSON comparison data
  - runtime_measurements/cache/evaluation.html: Human-readable HTML report
  - runtime_measurements/cache/*/cache.json: Per-folder precomputed data

Cache is only recomputed when file hashes change (manual update required).
"""

import hashlib
import json
import statistics
from datetime import datetime
from pathlib import Path

BASE_PATH = Path(__file__).resolve().parent.parent.parent.parent
RUNTIME_PATH = BASE_PATH / "runtime_measurements"
CACHE_PATH = RUNTIME_PATH / "cache"


# Version name mapping - rename pr_* and base_* for stability
def get_version_name(folder_name):
    """Map folder names to stable version identifiers."""
    if folder_name.startswith("pr_"):
        return "pr"
    elif folder_name.startswith("base_"):
        return "base"
    return folder_name


def compute_file_hash(filepath):
    """Compute SHA256 hash of a file."""
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


def compute_five_num_summary(values):
    """Compute 5-number summary (min, Q1, median, Q3, max)."""
    if not values:
        return {"min": 0, "q1": 0, "median": 0, "q3": 0, "max": 0}
    sorted_vals = sorted(values)
    n = len(sorted_vals)
    return {
        "min": sorted_vals[0],
        "q1": statistics.median(sorted_vals[: n // 2]),
        "median": statistics.median(sorted_vals),
        "q3": statistics.median(sorted_vals[(n + 1) // 2 :]),
        "max": sorted_vals[-1],
    }


def parse_report(filepath):
    """Parse a single SMDA JSON report and extract precomputed values."""
    with open(filepath) as f:
        data = json.load(f)

    xcfg = data.get("xcfg", {})
    total_insns = 0
    func_counts = {}
    for addr, func_data in xcfg.items():
        blocks = func_data.get("blocks", {})
        if isinstance(blocks, dict):
            num_insns = sum(len(ins_list) for ins_list in blocks.values())
        else:
            num_insns = sum(len(ins_list) for ins_list in blocks)
        func_counts[addr] = num_insns
        total_insns += num_insns

    exec_time = data.get("execution_time", 0)

    return {
        "function_count": len(func_counts),
        "instruction_counts": func_counts,
        "total_instructions": total_insns,
        "execution_time": exec_time,
        "functions_per_sec": len(func_counts) / exec_time if exec_time > 0 else 0,
        "instructions_per_sec": total_insns / exec_time if exec_time > 0 else 0,
        "file_hash": compute_file_hash(filepath),
    }


def get_cache_key(folder_name):
    """Generate cache file path for a folder."""
    return CACHE_PATH / folder_name / "cache.json"


def load_from_cache(folder_name):
    """Load precomputed data from cache if valid."""
    cache_file = get_cache_key(folder_name)
    if cache_file.exists():
        try:
            with open(cache_file) as f:
                return json.load(f)
        except (OSError, json.JSONDecodeError):
            pass
    return None


def cache_reports(folder_name):
    """Cache reports for a folder if not already cached or stale."""
    folder_path = RUNTIME_PATH / folder_name
    cache_file = get_cache_key(folder_name)

    cached = load_from_cache(folder_name)
    if cached is not None:
        # Check if all files still match their cached hashes
        all_valid = True
        for filename, cached_info in cached.items():
            filepath = folder_path / filename
            if not filepath.exists():
                all_valid = False
                break
            if compute_file_hash(filepath) != cached_info.get("file_hash", ""):
                all_valid = False
                break
        if all_valid:
            return cached

    # Parse and cache all reports
    cache_data = {}
    for json_file in folder_path.glob("*.smda"):
        filename = json_file.name
        cache_data[filename] = parse_report(json_file)

    # Save cache
    cache_file.parent.mkdir(parents=True, exist_ok=True)
    with open(cache_file, "w") as f:
        json.dump(cache_data, f, indent=2)

    return cache_data


def compare_reports(head_data, version_data, head_label, version_label):
    """
    Compare parsed reports between head and version.

    Returns comparison results dict.
    """
    results = {
        "head_folder": head_label,
        "version_folder": version_label,
        "head_label_stable": get_version_name(head_label),
        "version_label_stable": get_version_name(version_label),
        "total_head_files": len(head_data),
        "total_version_files": len(version_data),
        "common_files": sorted(set(head_data.keys()) & set(version_data.keys())),
        "only_in_head": sorted(set(head_data.keys()) - set(version_data.keys())),
        "only_in_version": sorted(set(version_data.keys()) - set(head_data.keys())),
        "function_count_matches": [],
        "function_count_mismatches": [],
        "address_mismatches": [],
        "execution_times": {"head": [], "version": []},
        "throughput": {
            "head_functions_per_sec": [],
            "head_instructions_per_sec": [],
            "version_functions_per_sec": [],
            "version_instructions_per_sec": [],
        },
    }

    for filename in results["common_files"]:
        head_info = head_data[filename]
        version_info = version_data[filename]

        # Compare function counts
        if head_info["function_count"] == version_info["function_count"]:
            results["function_count_matches"].append(filename)
        else:
            results["function_count_mismatches"].append(
                {
                    "file": filename,
                    "head_function_count": head_info["function_count"],
                    "version_function_count": version_info["function_count"],
                }
            )

        # Compare instruction counts per address
        head_addrs = set(head_info["instruction_counts"].keys())
        version_addrs = set(version_info["instruction_counts"].keys())

        if head_addrs != version_addrs:
            results["address_mismatches"].append(
                {
                    "file": filename,
                    "only_in_head": sorted(head_addrs - version_addrs),
                    "only_in_version": sorted(version_addrs - head_addrs),
                }
            )
        else:
            count_diffs = {
                addr: {
                    "head": head_info["instruction_counts"][addr],
                    "version": version_info["instruction_counts"][addr],
                }
                for addr in head_addrs
                if head_info["instruction_counts"][addr] != version_info["instruction_counts"][addr]
            }
            if count_diffs:
                results["address_mismatches"].append({"file": filename, "instruction_count_diffs": count_diffs})

        results["execution_times"]["head"].append(head_info["execution_time"])
        results["execution_times"]["version"].append(version_info["execution_time"])
        results["throughput"]["head_functions_per_sec"].append(head_info.get("functions_per_sec", 0))
        results["throughput"]["head_instructions_per_sec"].append(head_info.get("instructions_per_sec", 0))
        results["throughput"]["version_functions_per_sec"].append(version_info.get("functions_per_sec", 0))
        results["throughput"]["version_instructions_per_sec"].append(version_info.get("instructions_per_sec", 0))

    # Calculate medians (more robust against outliers)
    if results["execution_times"]["head"]:
        results["execution_times"]["median_head"] = statistics.median(results["execution_times"]["head"])
    if results["execution_times"]["version"]:
        results["execution_times"]["median_version"] = statistics.median(results["execution_times"]["version"])

    # Calculate means for comparison
    if results["execution_times"]["head"]:
        results["execution_times"]["avg_head"] = statistics.mean(results["execution_times"]["head"])
    if results["execution_times"]["version"]:
        results["execution_times"]["avg_version"] = statistics.mean(results["execution_times"]["version"])

    if "median_head" in results["execution_times"] and "median_version" in results["execution_times"]:
        results["execution_times"]["diff_median"] = (
            results["execution_times"]["median_head"] - results["execution_times"]["median_version"]
        )

    if "avg_head" in results["execution_times"] and "avg_version" in results["execution_times"]:
        results["execution_times"]["diff_avg"] = (
            results["execution_times"]["avg_head"] - results["execution_times"]["avg_version"]
        )

    if (
        "median_head" in results["execution_times"]
        and "median_version" in results["execution_times"]
        and results["execution_times"]["median_version"] > 0
    ):
        results["execution_times"]["speedup_percent"] = (
            (results["execution_times"]["median_version"] - results["execution_times"]["median_head"])
            / results["execution_times"]["median_version"]
            * 100
        )

    # Calculate throughput medians and 5-number summaries
    if results["throughput"]["head_functions_per_sec"]:
        results["throughput"]["median_head_functions_per_sec"] = statistics.median(
            results["throughput"]["head_functions_per_sec"]
        )
        results["throughput"]["median_version_functions_per_sec"] = statistics.median(
            results["throughput"]["version_functions_per_sec"]
        )
        results["throughput"]["median_head_instructions_per_sec"] = statistics.median(
            results["throughput"]["head_instructions_per_sec"]
        )
        results["throughput"]["median_version_instructions_per_sec"] = statistics.median(
            results["throughput"]["version_instructions_per_sec"]
        )
        # Add 5-number summaries for throughput analysis
        results["throughput"]["five_num_head_functions_per_sec"] = compute_five_num_summary(
            results["throughput"]["head_functions_per_sec"]
        )
        results["throughput"]["five_num_version_functions_per_sec"] = compute_five_num_summary(
            results["throughput"]["version_functions_per_sec"]
        )
        results["throughput"]["five_num_head_instructions_per_sec"] = compute_five_num_summary(
            results["throughput"]["head_instructions_per_sec"]
        )
        results["throughput"]["five_num_version_instructions_per_sec"] = compute_five_num_summary(
            results["throughput"]["version_instructions_per_sec"]
        )

    return results


def generate_markdown_report(all_results, output_path):
    """Generate Markdown report from comparison results."""
    head_times = []
    version_times = []
    for result in all_results:
        head_times.extend(result["execution_times"]["head"])
        version_times.extend(result["execution_times"]["version"])

    head_label = result["head_label_stable"] if all_results else "pr"
    version_label = result["version_label_stable"] if all_results else "base"

    head_med = statistics.median(head_times) if head_times else 0
    version_med = statistics.median(version_times) if version_times else 0
    diff = head_med - version_med
    pct_change = (diff / version_med) * 100 if version_med > 0 else 0

    md = f"""### 📊 SMDA Performance Evaluation Benchmark Results
*Generated on: {datetime.now().strftime("%Y-%m-%d %H:%M:%S")}*

#### Summary Overview
| Metric | {version_label} (Base) | {head_label} (PR) | Change |
| --- | --- | --- | --- |
| **Files Processed** | {len(version_times)} | {len(head_times)} | - |
| **Median Execution Time** | {version_med:.4f}s | {head_med:.4f}s | {diff:+.4f}s ({pct_change:+.2f}%) |
| **Overall Throughput** | ~{(len(version_times) * 1000) / sum(version_times) if version_times and sum(version_times) > 0 else 0:.0f} func/s | ~{(len(head_times) * 1000) / sum(head_times) if head_times and sum(head_times) > 0 else 0:.0f} func/s | - |

#### Detailed Comparison
| Comparison Run | {head_label} Files | {version_label} Files | Common | Function Count Matches | Med {head_label} (s) | Med {version_label} (s) | Med Diff (s) | Speedup % |
| --- | --- | --- | --- | --- | --- | --- | --- | --- |
"""
    for result in all_results:
        head_folder = result["head_folder"]
        version_folder = result["version_folder"]
        head_count = len(result["execution_times"]["head"])
        version_count = len(result["execution_times"]["version"])
        common_count = len(result["common_files"])
        match_count = len(result["function_count_matches"])

        h_med = result["execution_times"].get("median_head", 0)
        v_med = result["execution_times"].get("median_version", 0)
        d_med = result["execution_times"].get("diff_median", 0)
        speedup = result["execution_times"].get("speedup_percent", 0)

        md += f"| {head_folder} vs {version_folder} | {head_count} | {version_count} | {common_count} | {match_count}/{common_count} | {h_med:.4f}s | {v_med:.4f}s | {d_med:+.4f}s | {speedup:+.2f}% |\n"

        if result["function_count_mismatches"] or result["address_mismatches"]:
            md += "\n⚠️ **Correctness Mismatches Detected:**\n"
            for m in result["function_count_mismatches"][:5]:
                md += f"- `{m['file']}`: function count mismatch (Base: {m['version_function_count']}, PR: {m['head_function_count']})\n"
            for m in result["address_mismatches"][:5]:
                md += f"- `{m['file']}`: function address set mismatch\n"
            if len(result["function_count_mismatches"]) > 5 or len(result["address_mismatches"]) > 5:
                md += "- ... (some mismatches truncated)\n"

    with open(output_path, "w") as f:
        f.write(md)

    return output_path


