def main():
    """Main evaluation function."""
    print("=" * 80)
    print("SMDA Runtime Efficiency Evaluation")
    print("=" * 80)

    # Discover all folders
    if not RUNTIME_PATH.exists():
        print(f"Error: {RUNTIME_PATH} does not exist!")
        return

    head_folders = sorted([d.name for d in RUNTIME_PATH.iterdir() if d.is_dir() and d.name.startswith("pr_")])
    version_folders = sorted([d.name for d in RUNTIME_PATH.iterdir() if d.is_dir() and d.name.startswith("base_")])

    print(f"\nFound {len(head_folders)} pr_* folders: {', '.join(head_folders)}")
    print(f"Found {len(version_folders)} base_* folders: {', '.join(version_folders)}")

    if not head_folders:
        print("Error: No pr_* folders found!")
        return

    if not version_folders:
        print("Error: No base_* folders found!")
        return

    # CACHE ALL REPORTS FIRST
    print("\n" + "-" * 80)
    print("Caching reports...")
    print("-" * 80)

    all_caches = {}
    all_caches_throughput = {}
    for folder in head_folders + version_folders:
        print(f"  Processing {folder}...", end=" ")
        try:
            cache = cache_reports(folder)
            all_caches_throughput[folder] = {
                "total_functions": sum(r["function_count"] for r in cache.values()),
                "total_instructions": sum(r["total_instructions"] for r in cache.values()),
                "total_exec_time": sum(r["execution_time"] for r in cache.values()),
                "avg_functions_per_sec": statistics.mean([r["functions_per_sec"] for r in cache.values()])
                if cache
                else 0,
                "avg_instructions_per_sec": statistics.mean([r["instructions_per_sec"] for r in cache.values()])
                if cache
                else 0,
                "files_cached": len(cache),
            }
            print(f"{len(cache)} files cached")
            all_caches[folder] = cache
        except Exception as e:
            print(f"ERROR: {e}")

    # COMPARE ALL PAIRS
    print("\n" + "-" * 80)
    print("Comparing versions...")
    print("-" * 80)

    all_results = []

    for version_folder in version_folders:
        for head_folder in head_folders:
            head_label = get_version_name(head_folder)
            version_label = get_version_name(version_folder)
            print(f"\n  Comparing {version_folder} ({version_label}) vs {head_folder} ({head_label})...")

            head_data = all_caches[head_folder]
            version_data = all_caches[version_folder]

            results = compare_reports(head_data, version_data, head_label=head_folder, version_label=version_folder)

            all_results.append(results)

            # Print summary for this comparison
            common = len(results["common_files"])
            matches = len(results["function_count_matches"])
            print(f"    Common files: {common}, Function count matches: {matches}")
            if "median_head" in results["execution_times"] and "median_version" in results["execution_times"]:
                print(
                    f"    Median times: {head_label}={results['execution_times']['median_head']:.4f}s, "
                    f"{version_label}={results['execution_times']['median_version']:.4f}s, "
                    f"diff={results['execution_times']['diff_median']:+.4f}s"
                )

    # Generate outputs
    print("\n" + "-" * 80)
    print("Generating reports...")
    print("-" * 80)

    # Transform throughput summary to use stable version names
    stable_throughput = {}
    for folder, data in all_caches_throughput.items():
        stable_throughput[folder] = data

    # JSON output
    json_output = CACHE_PATH / "evaluation.json"
    full_output = {"comparisons": all_results, "throughput_summary": stable_throughput}
    with open(json_output, "w") as f:
        json.dump(full_output, f, indent=2)
    print(f"  JSON report: {json_output}")

    # HTML output
    html_output = CACHE_PATH / "evaluation.html"
    generate_html_report(all_results, html_output)
    print(f"  HTML report: {html_output}")

    # Markdown output
    md_output = CACHE_PATH / "evaluation.md"
    generate_markdown_report(all_results, md_output)
    print(f"  Markdown report: {md_output}")

    print("\n" + "=" * 80)
    print("Evaluation complete!")
    print("=" * 80)


if __name__ == "__main__":
    main()
